import * as core from "@actions/core";
import "cross-fetch/polyfill";
import { createClient } from "@scaleway/sdk-client";
import { Secretv1beta1 } from "@scaleway/sdk-secret";
import { extractAlias, getSecretValue } from "./utils";
export async function run() {
    try {
        const client = createClient({
            accessKey: core.getInput("access-key"),
            secretKey: core.getInput("secret-key"),
            defaultProjectId: core.getInput("default-project-id"),
            defaultOrganizationId: core.getInput("default-organization-id"),
            defaultRegion: core.getInput("default-region"),
            defaultZone: core.getInput("default-zone"),
        });
        const api = new Secretv1beta1.API(client);
        const secretConfigInputs = [
            ...new Set(core.getMultilineInput("secret-names")),
        ];
        for (let secretConf of secretConfigInputs) {
            const [envName, secret] = extractAlias(secretConf);
            try {
                const secretValue = await getSecretValue(api, secret);
                core.setSecret(secretValue);
                core.debug(`Injecting secret /${secret.path}/${secret.name} as environment variable '${envName}'.`);
                core.exportVariable(envName, secretValue);
            }
            catch (error) {
                core.setFailed(`Failed to fetch secret: '/${secret.path}/${secret.name}'. Error: ${error}.`);
            }
        }
    }
    catch (error) {
        if (error instanceof Error)
            core.setFailed(error.message);
    }
}
run();
